print(f"{(num1 := float(input('Insira o primeiro valor: '))) and ''}{(num2 := float(input('Insira o segundo valor: '))) and ''}{(operacao := int(input('Insira a operação a ser executada (1 - Adição, 2 - Subtração, 3 - Multiplicação, 4 - Divisão): '))) and ''}{(f'O resultado da adição é {num1 + num2}.' if operacao == 1 else (f'O resultado da subtração é {num1 - num2}.' if operacao == 2 else (f'O resultado da multiplicação é {num1 * num2}.' if operacao == 3 else f'O resultado da divisão é {num1 / num2}.' if operacao == 4 else 'Operação inválida.')))}")
